export default function createCleanupBag() {
  const cleanups = new Set();
  let disposed = false;

  const add = (fn) => {
    if (typeof fn !== 'function') throw new TypeError('cleanup must be a function');
    if (disposed) {
      fn();
      return () => {};
    }
    cleanups.add(fn);
    let removed = false;
    return () => {
      if (removed) return;
      removed = true;
      cleanups.delete(fn);
    };
  };

  const dispose = () => {
    if (disposed) return;
    disposed = true;
    for (const fn of Array.from(cleanups)) {
      try { fn(); } finally { cleanups.delete(fn); }
    }
  };

  const size = () => cleanups.size;

  return { add, dispose, size };
}
